code.C:
#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int i = 0; i < T; ++i) {
        char url[101];
        if (!fgets(url, sizeof(url), stdin)) break;
        size_t len = strlen(url);
        if (len && url[len-1] == '\n') url[len-1] = '\0'; // remove trailing newline
        printf("Short URL: short%d, Access Count: 0\n", i);
    }
    return 0;
}

