        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        for (int i = 0; i < T; i++) {
            br.readLine(); // read URL, not needed for output
            System.out.println("Short URL: short" + i + ", Access Count: 0");
